C++<pre><code>#include &lt;iostream&gt;
#include &lt;algorithm&gt;
#include &lt;cstring&gt;

using namespace std;

const int N = 100;
int a[N], b[N];

// 插入排序
void insertsort(int a[], int n)
{
    for (int i = 2; i &lt;= n; i++)
    {
        a[0] = a[i];
        int j = i - 1;
        while (a[0] &lt; a[j])
        {
            a[j + 1] = a[j];
            j--;
        }
        a[j + 1] = a[0];
    }
}

// 折半插入排序
void binarysort(int a[], int n)
{
    int i, j, low, high, mid;
    for (int i = 2; i &lt;= n; i++)
    {
        a[0] = a[i];
        low = 1, high = i - 1;
        while (low &lt;= high)
        {
            mid = (low + high) / 2;
            if (a[mid] &gt; a[0])
                high = mid - 1;
            else
                low = mid + 1;
        }
        for (int j = i - 1; j &gt;= low; j--)
            a[j + 1] = a[0];
        a[low] = a[0];
    }
}

// 希尔排序
void shellsort(int a[], int n)
{
    int d, i, j;
    for (d = n / 2; d &gt;= 1; d = d / 2)
    {
        for (i = d + 1; i &lt;= n; i++)
        {
            if (a[i] &lt; a[i - d])
            {
                a[0] = a[i];
                for (j = i - d; j &gt; 0 &amp;&amp; a[0] &lt; a[j]; j--)
                    a[j + d] = a[j];
                a[j + d] = a[0];
            }
        }
    }
}

// 冒泡排序
void bubblesort(int a[], int n)
{
    for (int i = 0; i &lt; n - 1; i++)
    {
        bool flag = false;
        for (int j = n - 1; j &gt; i; j--)
        {
            if (a[j - 1] &gt; a[j])
            {
                swap(a[j - 1], a[j]);
                flag = true;
            }
        }
        if (flag == false)
            return;
    }
}

// 快速排序
int Partition(int a[], int low, int high)
{
    int pivot = a[low];
    while (low &lt; high)
    {
        while (low &lt; high &amp;&amp; a[high] &gt;= pivot)
            high--;
        a[low] = a[high];
        while (low &lt; high &amp;&amp; a[low] &lt;= pivot)
            low++;
        a[high] = a[low];
    }
    a[low] = pivot;
    return low;
}

void quicksort(int a[], int s, int t)
{
    if (s &lt; t)
    {
        int pivotloc = Partition(a, s, t);
        quicksort(a, s, pivotloc - 1);
        quicksort(a, pivotloc + 1, t);
    }
}

// 简单选择排序
void slectsort(int a[], int n)
{
    for (int i = 0; i &lt; n - 1; i++)
    {
        int j = i;
        for (int k = j + 1; k &lt;= n; k++)
        {
            if (a[k] &lt; a[j])
                j = k;
        }
        if (i != j)
            swap(a[i], a[j]);
    }
}

// 堆排序
void HeapAdjust(int a[], int k, int n)
{
    a[0] = a[k];
    for (int i = 2 * k; i &lt;= n; i = i * 2)
    {
        if (i &lt; n &amp;&amp; a[i] &lt; a[i + 1])
            i++;
        if (a[0] &gt; a[i])
            break;
        else
        {
            a[k] = a[i];
            k = i;
        }
    }
    a[k] = a[0];
}

void BuildMaxHeap(int a[], int n)
{
    for (int i = n / 2; i &gt; 0; i--)
        HeapAdjust(a, i, n);
}

void Heapsort(int a[], int n)
{
    BuildMaxHeap(a, n);
    for (int i = n; i &gt; 1; i--)
    {
        swap(a[i], a[1]);
        HeapAdjust(a, 1, i - 1);
    }
}

// 归并排序

void merge(int a[], int low, int mid, int high)
{
    int i, j, k;
    for (int k = low; k &lt;= high; k++)
        b[k] = a[k];

    for (i = low, j = mid + 1, k = i; i &lt;= mid &amp;&amp; j &lt;= high; k++)
    {
        if (b[i] &lt;= b[j])
            a[k] = b[i++];
        else
            a[k] = b[j++];
    }
    while (i &lt;= mid)
        a[k++] = b[i++];
    while (j &lt;= high)
        a[k++] = b[j++];
}

void mergesort(int a[], int low, int high)
{
    if (low &lt; high)
    {
        int mid = (low + high) / 2;
        mergesort(a, low, mid);
        mergesort(a, mid + 1, high);
        merge(a, low, mid, high);
    }
}
